      "properties": {
        "build": {
          "type": "object",
          "properties": {
            "model": {
              "type": "string"
            },
            "fallback_models": {
              "anyOf": [
                {
                  "type": "string"
                },
                {
                  "type": "array",
                  "items": {
                    "anyOf": [
                      {
                        "type": "string"
                      },
                      {
                        "type": "object",
                        "properties": {
                          "model": {
                            "type": "string"
                          },
                          "variant": {
                            "type": "string"
                          },
                          "reasoningEffort": {
                            "type": "string",
