                                  "enabled",
                                  "disabled"
                                ]
                              },
                              "budgetTokens": {
                                "type": "number"
                              }
                            },
                            "required": [
                              "type"
                            ],
                            "additionalProperties": false
                          }
                        },
                        "required": [
                          "model"
                        ],
                        "additionalProperties": false
                      }
                    ]
                  }
                }
              ]
            },
            "variant": {
              "type": "string"
            },
            "category": {
              "type": "string"
            },
            "skills": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "temperature": {
              "type": "number",
              "minimum": 0,
              "maximum": 2
            },
            "top_p": {
              "type": "number",
              "minimum": 0,
              "maximum": 1
            },
            "prompt": {
              "type": "string"
            },
            "prompt_append": {
              "type": "string"
            },
            "tools": {
              "type": "object",
              "propertyNames": {
                "type": "string"
              },
              "additionalProperties": {
                "type": "boolean"
              }
            },
            "disable": {
              "type": "boolean"
            },
            "description": {

          "minimum": 1,
          "maximum": 9007199254740991
        },
        "maxDescendants": {
          "type": "integer",
          "minimum": 1,
          "maximum": 9007199254740991
        },
        "staleTimeoutMs": {
          "type": "number",
          "minimum": 60000
        },
        "messageStalenessTimeoutMs": {
          "type": "number",
          "minimum": 60000
        },
        "taskTtlMs": {
          "type": "number",
          "minimum": 300000
        },
        "sessionGoneTimeoutMs": {
          "type": "number",
          "minimum": 10000
        },
        "syncPollTimeoutMs": {
          "type": "number",
          "minimum": 60000
        },
        "maxToolCalls": {
          "type": "integer",
          "minimum": 10,
          "maximum": 9007199254740991
        },
        "circuitBreaker": {
          "type": "object",
          "properties": {
            "enabled": {
              "type": "boolean"
            },
            "maxToolCalls": {
              "type": "integer",
              "minimum": 10,
              "maximum": 9007199254740991
            },
            "consecutiveThreshold": {
              "type": "integer",
              "minimum": 5,
              "maximum": 9007199254740991
            }
          },
          "additionalProperties": false
        }
      },
      "additionalProperties": false
    },
    "notification": {
      "type": "object",
      "properties": {
        "force_enable": {
          "type": "boolean"
        }
