        "enabled": {
          "default": false,
          "type": "boolean"
        },
        "gateways": {
          "default": {},
          "type": "object",
          "propertyNames": {
            "type": "string"
          },
          "additionalProperties": {
            "type": "object",
            "properties": {
              "type": {
                "default": "http",
                "type": "string",
                "enum": [
                  "http",
                  "command"
                ]
              },
              "url": {
                "type": "string"
              },
              "method": {
                "default": "POST",
                "type": "string"
