              "enabled": {
                "default": true,
                "type": "boolean"
              },
              "gateway": {
                "type": "string"
              },
              "instruction": {
                "type": "string"
              }
            },
            "required": [
              "enabled",
              "gateway",
              "instruction"
            ],
            "additionalProperties": false
          }
        },
        "replyListener": {
          "type": "object",
