            "telegramBotToken": {
              "type": "string"
            },
            "telegramChatId": {
              "type": "string"
            },
            "pollIntervalMs": {
              "default": 3000,
              "type": "number"
            },
            "rateLimitPerMinute": {
              "default": 10,
              "type": "number"
            },
            "maxMessageLength": {
              "default": 500,
              "type": "number"
            },
            "includePrefix": {
              "default": true,
              "type": "boolean"
            }
          },
          "required": [
            "authorizedDiscordUserIds",
            "pollIntervalMs",
            "rateLimitPerMinute",
            "maxMessageLength",
            "includePrefix"
          ],
          "additionalProperties": false
        }
      },
      "required": [
        "enabled",
        "gateways",
        "hooks"
      ],
      "additionalProperties": false
    },
    "babysitting": {
      "type": "object",
      "properties": {
        "timeout_ms": {
          "default": 120000,
          "type": "number"
        }
      },
      "required": [
        "timeout_ms"
      ],
      "additionalProperties": false
    },
