      "default": {
        "commit_footer": true,
        "include_co_authored_by": true,
        "git_env_prefix": "GIT_MASTER=1"
      },
      "type": "object",
      "properties": {
        "commit_footer": {
          "default": true,
          "anyOf": [
            {
              "type": "boolean"
            },
            {
              "type": "string"
            }
