      "type": "object",
      "properties": {
        "provider": {
          "default": "playwright",
          "type": "string",
          "enum": [
            "playwright",
            "agent-browser",
            "dev-browser",
            "playwright-cli"
          ]
        }
      },
      "required": [
        "provider"
      ],
      "additionalProperties": false
