    "websearch": {
      "type": "object",
      "properties": {
        "provider": {
          "type": "string",
          "enum": [
            "exa",
            "tavily"
          ]
        }
      },
      "additionalProperties": false
    },
    "tmux": {
      "type": "object",
      "properties": {
        "enabled": {
          "default": false,
          "type": "boolean"
