            "main-horizontal",
            "main-vertical",
            "tiled",
            "even-horizontal",
            "even-vertical"
          ]
        },
        "main_pane_size": {
          "default": 60,
          "type": "number",
          "minimum": 20,
          "maximum": 80
        },
        "main_pane_min_width": {
          "default": 120,
          "type": "number",
          "minimum": 40
