        "agent_pane_min_width": {
          "default": 40,
          "type": "number",
          "minimum": 20
        }
      },
      "required": [
        "enabled",
        "layout",
        "main_pane_size",
        "main_pane_min_width",
        "agent_pane_min_width"
      ],
      "additionalProperties": false
    },
    "sisyphus": {
      "type": "object",
      "properties": {
        "tasks": {
          "type": "object",
          "properties": {
            "storage_path": {
              "type": "string"
            },
            "task_list_id": {
              "type": "string"
            },
            "claude_code_compat": {
              "default": false,
              "type": "boolean"
